(window.webpackJsonp=window.webpackJsonp||[]).push([[729],{696:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">n</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[][]}</span> <span class=\\"hljs-variable\\">edges</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">distanceThreshold</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> findTheCity = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">n, edges, distanceThreshold</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> path=<span class=\\"hljs-built_in\\">Array</span>(n).fill().map(<span class=\\"hljs-function\\"><span class=\\"hljs-params\\">()</span>=&gt;</span><span class=\\"hljs-built_in\\">Array</span>(n).fill(<span class=\\"hljs-literal\\">Infinity</span>))\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;n;i++){\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> j=<span class=\\"hljs-number\\">0</span>;j&lt;n;j++){\\n      <span class=\\"hljs-keyword\\">if</span>(i===j)path[i][j]=<span class=\\"hljs-number\\">0</span>\\n    }\\n  }\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;edges.length;i++){\\n    <span class=\\"hljs-keyword\\">let</span> [<span class=\\"hljs-keyword\\">from</span>,to,w]=edges[i]\\n    path[<span class=\\"hljs-keyword\\">from</span>][to]=w\\n    path[to][<span class=\\"hljs-keyword\\">from</span>]=w\\n  }\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> k=<span class=\\"hljs-number\\">0</span>;k&lt;n;k++){\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;n;i++){\\n      <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> j=<span class=\\"hljs-number\\">0</span>;j&lt;n;j++){\\n        <span class=\\"hljs-keyword\\">if</span>(path[i][j]&gt;path[i][k]+path[k][j]){\\n          path[i][j]=path[i][k]+path[k][j]\\n        }\\n      }\\n    }\\n  }\\n  <span class=\\"hljs-keyword\\">let</span> record=<span class=\\"hljs-built_in\\">Array</span>(n).fill(<span class=\\"hljs-number\\">0</span>)\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;n;i++){\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> j=<span class=\\"hljs-number\\">0</span>;j&lt;n;j++){\\n      <span class=\\"hljs-keyword\\">if</span>(i===j)<span class=\\"hljs-keyword\\">continue</span>\\n      <span class=\\"hljs-keyword\\">if</span>(path[i][j]&lt;=distanceThreshold){\\n        record[i]++\\n      }\\n    }\\n  }\\n  <span class=\\"hljs-keyword\\">let</span> min=<span class=\\"hljs-literal\\">Infinity</span>\\n  <span class=\\"hljs-keyword\\">let</span> ans=<span class=\\"hljs-literal\\">null</span>\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=record.length<span class=\\"hljs-number\\">-1</span>;i&gt;=<span class=\\"hljs-number\\">0</span>;i--){\\n    <span class=\\"hljs-keyword\\">if</span>(record[i]&lt;min){\\n      min=record[i]\\n      ans=i\\n    }\\n  }\\n  <span class=\\"hljs-keyword\\">return</span> ans\\n};\\n</code></pre>\\n"],"titleSlug":"find-the-city-with-the-smallest-number-of-neighbors-at-a-threshold-distance","hasThinking":false,"content":"<p>\u6709 <code>n</code>\xa0\u4e2a\u57ce\u5e02\uff0c\u6309\u4ece <code>0</code> \u5230 <code>n-1</code>\xa0\u7f16\u53f7\u3002\u7ed9\u4f60\u4e00\u4e2a\u8fb9\u6570\u7ec4\xa0<code>edges</code>\uff0c\u5176\u4e2d <code>edges[i] = [from<sub>i</sub>, to<sub>i</sub>, weight<sub>i</sub>]</code>\xa0\u4ee3\u8868\xa0<code>from<sub>i</sub></code>\xa0\u548c\xa0<code>to<sub>i</sub></code><sub>\xa0</sub>\u4e24\u4e2a\u57ce\u5e02\u4e4b\u95f4\u7684\u53cc\u5411\u52a0\u6743\u8fb9\uff0c\u8ddd\u79bb\u9608\u503c\u662f\u4e00\u4e2a\u6574\u6570\xa0<code>distanceThreshold</code>\u3002</p>\\n\\n<p>\u8fd4\u56de\u80fd\u901a\u8fc7\u67d0\u4e9b\u8def\u5f84\u5230\u8fbe\u5176\u4ed6\u57ce\u5e02\u6570\u76ee\u6700\u5c11\u3001\u4e14\u8def\u5f84\u8ddd\u79bb <strong>\u6700\u5927</strong> \u4e3a\xa0<code>distanceThreshold</code>\xa0\u7684\u57ce\u5e02\u3002\u5982\u679c\u6709\u591a\u4e2a\u8fd9\u6837\u7684\u57ce\u5e02\uff0c\u5219\u8fd4\u56de\u7f16\u53f7\u6700\u5927\u7684\u57ce\u5e02\u3002</p>\\n\\n<p>\u6ce8\u610f\uff0c\u8fde\u63a5\u57ce\u5e02 <em><strong>i</strong></em> \u548c <em><strong>j</strong></em> \u7684\u8def\u5f84\u7684\u8ddd\u79bb\u7b49\u4e8e\u6cbf\u8be5\u8def\u5f84\u7684\u6240\u6709\u8fb9\u7684\u6743\u91cd\u4e4b\u548c\u3002</p>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<p><img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2020/01/26/find_the_city_01.png\\" style=\\"height: 225px; width: 300px;\\" /></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>n = 4, edges = [[0,1,3],[1,2,1],[1,3,4],[2,3,1]], distanceThreshold = 4\\n<strong>\u8f93\u51fa\uff1a</strong>3\\n<strong>\u89e3\u91ca\uff1a</strong>\u57ce\u5e02\u5206\u5e03\u56fe\u5982\u4e0a\u3002\\n\u6bcf\u4e2a\u57ce\u5e02\u9608\u503c\u8ddd\u79bb distanceThreshold = 4 \u5185\u7684\u90bb\u5c45\u57ce\u5e02\u5206\u522b\u662f\uff1a\\n\u57ce\u5e02 0 -> [\u57ce\u5e02 1, \u57ce\u5e02 2]\xa0\\n\u57ce\u5e02 1 -> [\u57ce\u5e02 0, \u57ce\u5e02 2, \u57ce\u5e02 3]\xa0\\n\u57ce\u5e02 2 -> [\u57ce\u5e02 0, \u57ce\u5e02 1, \u57ce\u5e02 3]\xa0\\n\u57ce\u5e02 3 -> [\u57ce\u5e02 1, \u57ce\u5e02 2]\xa0\\n\u57ce\u5e02 0 \u548c 3 \u5728\u9608\u503c\u8ddd\u79bb 4 \u4ee5\u5185\u90fd\u6709 2 \u4e2a\u90bb\u5c45\u57ce\u5e02\uff0c\u4f46\u662f\u6211\u4eec\u5fc5\u987b\u8fd4\u56de\u57ce\u5e02 3\uff0c\u56e0\u4e3a\u5b83\u7684\u7f16\u53f7\u6700\u5927\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<p><strong><img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2020/01/26/find_the_city_02.png\\" style=\\"height: 225px; width: 300px;\\" /></strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>n = 5, edges = [[0,1,2],[0,4,8],[1,2,3],[1,4,2],[2,3,1],[3,4,1]], distanceThreshold = 2\\n<strong>\u8f93\u51fa\uff1a</strong>0\\n<strong>\u89e3\u91ca\uff1a</strong>\u57ce\u5e02\u5206\u5e03\u56fe\u5982\u4e0a\u3002\xa0\\n\u6bcf\u4e2a\u57ce\u5e02\u9608\u503c\u8ddd\u79bb distanceThreshold = 2 \u5185\u7684\u90bb\u5c45\u57ce\u5e02\u5206\u522b\u662f\uff1a\\n\u57ce\u5e02 0 -> [\u57ce\u5e02 1]\xa0\\n\u57ce\u5e02 1 -> [\u57ce\u5e02 0, \u57ce\u5e02 4]\xa0\\n\u57ce\u5e02 2 -> [\u57ce\u5e02 3, \u57ce\u5e02 4]\xa0\\n\u57ce\u5e02 3 -> [\u57ce\u5e02 2, \u57ce\u5e02 4]\\n\u57ce\u5e02 4 -> [\u57ce\u5e02 1, \u57ce\u5e02 2, \u57ce\u5e02 3]\xa0\\n\u57ce\u5e02 0 \u5728\u9608\u503c\u8ddd\u79bb 2 \u4ee5\u5185\u53ea\u6709 1 \u4e2a\u90bb\u5c45\u57ce\u5e02\u3002\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>2 <= n <= 100</code></li>\\n\\t<li><code>1 <= edges.length <= n * (n - 1) / 2</code></li>\\n\\t<li><code>edges[i].length == 3</code></li>\\n\\t<li><code>0 <= from<sub>i</sub> < to<sub>i</sub> < n</code></li>\\n\\t<li><code>1 <= weight<sub>i</sub>,\xa0distanceThreshold <= 10^4</code></li>\\n\\t<li>\u6240\u6709 <code>(from<sub>i</sub>, to<sub>i</sub>)</code>\xa0\u90fd\u662f\u4e0d\u540c\u7684\u3002</li>\\n</ul>\\n","title":"1334. \u9608\u503c\u8ddd\u79bb\u5185\u90bb\u5c45\u6700\u5c11\u7684\u57ce\u5e02","relatedTags":["\u56fe"],"difficult":"Middle","lang":["javascript"],"uniqueID":"1334"}')}}]);